const FIXED_CASH = 200000;
const CITY_THRESHOLD = 300;
const HOUSE_TYPE_THRESHOLD = 100;
const CITY_HOUSE_THRESHOLD = 20;

const metricOptions = {
  adjusted_occupancy_rate: { label: 'Adjusted Occupancy Rate', formatter: formatPercent },
  adj_airbnb_yroi: { label: 'ADJ_AIRBNB_YROI', formatter: formatPercent },
  rent_yroi: { label: 'RENT_YROI', formatter: formatPercent },
  roi_ratio: { label: 'ROI_RATIO', formatter: formatRatio },
  adj_airbnb_new: { label: 'ADJ_AIRBNB_NEW', formatter: formatCurrency },
  annual_airbnb_rent: { label: 'Annual Airbnb Rent', formatter: formatCurrency },
  annual_rent: { label: 'Annual Rent', formatter: formatCurrency },
  service_cost_new: { label: 'Service Cost', formatter: formatCurrency },
  house_price: { label: 'House Price', formatter: formatCurrency },
  price_per_night: { label: 'Price per Night', formatter: formatCurrency }
};

const state = {
  city: 'All',
  houseType: 'All',
  metric: 'adj_airbnb_yroi',
  sort: 'desc',
  budget: 900000,
  interestRate: 0.025,
  search: ''
};

const elements = {
  cityFilter: document.getElementById('cityFilter'),
  houseTypeFilter: document.getElementById('houseTypeFilter'),
  metricFilter: document.getElementById('metricFilter'),
  sortFilter: document.getElementById('sortFilter'),
  budgetSlider: document.getElementById('budgetSlider'),
  budgetValue: document.getElementById('budgetValue'),
  interestSlider: document.getElementById('interestSlider'),
  interestValue: document.getElementById('interestValue'),
  searchInput: document.getElementById('searchInput'),
  tableBody: document.getElementById('decisionTableBody'),
  tableCaption: document.getElementById('tableCaption'),
  metricsNotice: document.getElementById('metricsNotice')
};

function toValidNumbers(values) {
  return values.filter((value) => typeof value === 'number' && !Number.isNaN(value));
}

function mean(values) {
  const valid = toValidNumbers(values);
  return valid.length ? valid.reduce((sum, value) => sum + value, 0) / valid.length : null;
}

function sum(values) {
  const valid = toValidNumbers(values);
  return valid.length ? valid.reduce((acc, value) => acc + value, 0) : 0;
}

function formatCurrency(value) {
  if (value === null || value === undefined || Number.isNaN(value)) return 'N/A';
  return new Intl.NumberFormat('en-US', { style: 'currency', currency: 'EUR', maximumFractionDigits: 0 }).format(value);
}

function formatPercent(value) {
  if (value === null || value === undefined || Number.isNaN(value)) return 'N/A';
  return (value * 100).toFixed(2) + '%';
}

function formatRatio(value) {
  if (value === null || value === undefined || Number.isNaN(value)) return 'N/A';
  return value.toFixed(2) + 'x';
}

function formatNumber(value) {
  if (value === null || value === undefined || Number.isNaN(value)) return 'N/A';
  return new Intl.NumberFormat('en-US', { maximumFractionDigits: 0 }).format(value);
}

function setMetricNotice() {
  elements.metricsNotice.textContent = 'Adjusted Occupancy Rate is reconstructed from the Step 4 occupancy field in the sensitivity output. Budget, Loan Amount, Interest Rate, and Difference Total are interactive scenario calculations based on the current dashboard selection.';
}

function uniqueSorted(items, key) {
  return [...new Set(items.map((item) => item[key]).filter(Boolean))].sort((a, b) => String(a).localeCompare(String(b)));
}

function fillSelect(select, values) {
  select.innerHTML = '';
  ['All', ...values].forEach((value) => {
    const option = document.createElement('option');
    option.value = value;
    option.textContent = value;
    select.appendChild(option);
  });
}

function initialiseControls() {
  fillSelect(elements.cityFilter, uniqueSorted(DASHBOARD_DATA, 'city'));
  fillSelect(elements.houseTypeFilter, uniqueSorted(DASHBOARD_DATA, 'house_type'));

  Object.entries(metricOptions).forEach(([value, config]) => {
    const option = document.createElement('option');
    option.value = value;
    option.textContent = config.label;
    elements.metricFilter.appendChild(option);
  });

  elements.cityFilter.value = state.city;
  elements.houseTypeFilter.value = state.houseType;
  elements.metricFilter.value = state.metric;
  elements.sortFilter.value = state.sort;
  elements.budgetSlider.value = state.budget;
  elements.interestSlider.value = state.interestRate;
  updateSliderLabels();

  elements.cityFilter.addEventListener('change', () => { state.city = elements.cityFilter.value; render(); });
  elements.houseTypeFilter.addEventListener('change', () => { state.houseType = elements.houseTypeFilter.value; render(); });
  elements.metricFilter.addEventListener('change', () => { state.metric = elements.metricFilter.value; render(); });
  elements.sortFilter.addEventListener('change', () => { state.sort = elements.sortFilter.value; render(); });
  elements.budgetSlider.addEventListener('input', () => { state.budget = Number(elements.budgetSlider.value); updateSliderLabels(); render(); });
  elements.interestSlider.addEventListener('input', () => { state.interestRate = Number(elements.interestSlider.value); updateSliderLabels(); render(); });
  elements.searchInput.addEventListener('input', () => { state.search = elements.searchInput.value.trim().toLowerCase(); render(); });
}

function updateSliderLabels() {
  elements.budgetValue.textContent = formatCurrency(state.budget);
  elements.interestValue.textContent = formatPercent(state.interestRate);
}

function filteredRows() {
  return DASHBOARD_DATA.filter((row) => {
    const cityMatch = state.city === 'All' || row.city === state.city;
    const typeMatch = state.houseType === 'All' || row.house_type === state.houseType;
    return cityMatch && typeMatch;
  });
}

function groupRows(rows, keyBuilder) {
  return rows.reduce((acc, row) => {
    const key = keyBuilder(row);
    if (!acc[key]) acc[key] = [];
    acc[key].push(row);
    return acc;
  }, {});
}

function aggregateCityStats(rows) {
  const groups = groupRows(rows, (row) => row.city || 'Unknown');
  return Object.entries(groups).map(([city, bucket]) => {
    const houseCount = sum(bucket.map((row) => row.number_airbnb_house));
    return {
      city,
      rows: bucket,
      rowCount: bucket.length,
      houseCount,
      adjusted_occupancy_rate: mean(bucket.map((row) => row.adjusted_occupancy_rate)),
      adj_airbnb_yroi: mean(bucket.map((row) => row.adj_airbnb_yroi)),
      rent_yroi: mean(bucket.map((row) => row.rent_yroi)),
      roi_ratio: mean(bucket.map((row) => row.roi_ratio)),
      house_price: mean(bucket.map((row) => row.house_price))
    };
  });
}

function aggregateHouseTypeStats(rows) {
  const groups = groupRows(rows, (row) => row.house_type || 'Unknown');
  return Object.entries(groups).map(([houseType, bucket]) => {
    const houseCount = sum(bucket.map((row) => row.number_airbnb_house));
    return {
      houseType,
      rows: bucket,
      houseCount,
      adj_airbnb_yroi: mean(bucket.map((row) => row.adj_airbnb_yroi)),
      rent_yroi: mean(bucket.map((row) => row.rent_yroi)),
      adjusted_occupancy_rate: mean(bucket.map((row) => row.adjusted_occupancy_rate))
    };
  });
}

function aggregateCityHouseStats(rows) {
  const groups = groupRows(rows, (row) => `${row.city}|||${row.house_type}`);
  return Object.entries(groups).map(([compoundKey, bucket]) => {
    const [city, houseType] = compoundKey.split('|||');
    const houseCount = sum(bucket.map((row) => row.number_airbnb_house));
    return {
      city,
      houseType,
      label: `${city} | ${houseType}`,
      rows: bucket,
      houseCount,
      adjusted_occupancy_rate: mean(bucket.map((row) => row.adjusted_occupancy_rate)),
      adj_airbnb_yroi: mean(bucket.map((row) => row.adj_airbnb_yroi)),
      rent_yroi: mean(bucket.map((row) => row.rent_yroi)),
      roi_ratio: mean(bucket.map((row) => row.roi_ratio)),
      adj_airbnb_new: mean(bucket.map((row) => row.adj_airbnb_new)),
      annual_rent: mean(bucket.map((row) => row.annual_rent)),
      house_price: mean(bucket.map((row) => row.house_price)),
      price_per_night: mean(bucket.map((row) => row.price_per_night)),
      local_annual_taxes: mean(bucket.map((row) => row.local_annual_taxes)),
      service_cost_new: mean(bucket.map((row) => row.service_cost_new))
    };
  });
}

function sortByMetric(items, metric) {
  return [...items].filter((item) => item[metric] !== null && item[metric] !== undefined).sort((a, b) => state.sort === 'asc' ? a[metric] - b[metric] : b[metric] - a[metric]);
}

function getScenario(rows) {
  const cityStats = aggregateCityStats(rows);
  const screenedCities = cityStats.filter((city) => city.houseCount >= CITY_THRESHOLD);
  const eligibleCities = sortByMetric(screenedCities.length ? screenedCities : cityStats, 'adjusted_occupancy_rate');
  const topCities = eligibleCities.slice(0, 10).map((city) => city.city);
  const rowsInTopCities = rows.filter((row) => topCities.includes(row.city));
  const houseTypeStats = aggregateHouseTypeStats(rowsInTopCities);
  const screenedHouseTypes = houseTypeStats.filter((type) => type.houseCount >= HOUSE_TYPE_THRESHOLD);
  const eligibleHouseTypes = sortByMetric(screenedHouseTypes.length ? screenedHouseTypes : houseTypeStats, 'adj_airbnb_yroi');
  const cityHouseStats = aggregateCityHouseStats(rowsInTopCities);
  const screenedCityHouse = cityHouseStats.filter((item) => item.houseCount >= CITY_HOUSE_THRESHOLD);
  const rankedCityHouse = sortByMetric(screenedCityHouse.length ? screenedCityHouse : cityHouseStats, 'adj_airbnb_yroi');
  return { eligibleCities, topCities, rowsInTopCities, eligibleHouseTypes, rankedCityHouse };
}

function setCard(id, value, note) {
  const root = document.getElementById(id);
  root.querySelector('.kpi-value').textContent = value;
  root.querySelector('.kpi-subtle').textContent = note || '';
}

function cumulativeFinancialRows(rows) {
  let runningTotal = 0;
  return rows.map((row) => {
    runningTotal += row.house_price || 0;
    const differenceTotal = state.budget - runningTotal;
    const scenarioLoanAmount = Math.max(state.budget - FIXED_CASH, 0);
    const annualInterestCost = scenarioLoanAmount * state.interestRate;
    const estimatedNetAfterInterest = (row.adj_airbnb_new || 0) - (row.service_cost_new || 0) - (row.local_annual_taxes || 0) - annualInterestCost;
    return { ...row, cumulativeHousePrice: runningTotal, differenceTotal, scenarioLoanAmount, annualInterestCost, estimatedNetAfterInterest };
  });
}

function getDecisionRows(rows, rankedCityHouse) {
  const allowed = new Set(rankedCityHouse.map((item) => `${item.city}|||${item.houseType}`));
  let candidates = rows.filter((row) => allowed.has(`${row.city}|||${row.house_type}`));
  const budgetScoped = candidates.filter((row) => (row.house_price || 0) <= state.budget);
  if (budgetScoped.length) {
    candidates = budgetScoped;
  }
  if (state.search) {
    candidates = candidates.filter((row) => `${row.city} ${row.house_type}`.toLowerCase().includes(state.search));
  }
  candidates = [...candidates].sort((a, b) => {
    const av = a[state.metric] ?? -Infinity;
    const bv = b[state.metric] ?? -Infinity;
    return state.sort === 'asc' ? av - bv : bv - av;
  }).slice(0, 25);
  return cumulativeFinancialRows(candidates);
}

function renderKpis(rows, scenario, decisionRows) {
  const avgOccupancy = mean(rows.map((row) => row.adjusted_occupancy_rate));
  const avgAdjYroi = mean(rows.map((row) => row.adj_airbnb_yroi));
  const avgRentYroi = mean(rows.map((row) => row.rent_yroi));
  const bestCity = scenario.eligibleCities[0];
  const bestHouseType = scenario.eligibleHouseTypes[0];
  const totalHousePrice = sum(decisionRows.map((row) => row.house_price));
  const differenceTotal = state.budget - totalHousePrice;
  const loanAmount = Math.max(state.budget - FIXED_CASH, 0);

  setCard('kpiEligibleCities', formatNumber(scenario.eligibleCities.length), 'Cities passing the occupancy-led screening threshold');
  setCard('kpiAvgOccupancy', formatPercent(avgOccupancy), 'Average adjusted occupancy rate in the current selection');
  setCard('kpiAdjYroi', formatPercent(avgAdjYroi), 'Average ADJ_AIRBNB_YROI');
  setCard('kpiRentYroi', formatPercent(avgRentYroi), 'Average RENT_YROI');
  setCard('kpiBestCity', bestCity ? bestCity.city : 'N/A', bestCity ? `${formatPercent(bestCity.adjusted_occupancy_rate)} occupancy-led score` : 'No eligible city under current filters');
  setCard('kpiBestType', bestHouseType ? bestHouseType.houseType : 'N/A', bestHouseType ? `${formatPercent(bestHouseType.adj_airbnb_yroi)} ADJ_AIRBNB_YROI` : 'No eligible house type under current filters');
  setCard('kpiTotalHousePrice', formatCurrency(totalHousePrice), 'Sum of the top 25 decision rows currently shown');
  setCard('kpiDifferenceTotal', formatCurrency(differenceTotal), differenceTotal >= 0 ? 'Positive budget gap' : 'Budget exceeded by current visible selection');
  setCard('kpiLoanAmount', formatCurrency(loanAmount), `Based on fixed cash of ${formatCurrency(FIXED_CASH)} and interest rate ${formatPercent(state.interestRate)}`);
}

function plotTopCities(scenario) {
  const items = scenario.eligibleCities.slice(0, 10);
  Plotly.newPlot('topCitiesChart', [{
    type: 'bar',
    orientation: 'h',
    y: items.map((item) => item.city).reverse(),
    x: items.map((item) => item.adjusted_occupancy_rate).reverse(),
    marker: { color: '#1c4f7a' },
    hovertemplate: '%{y}<br>Adjusted Occupancy Rate: %{x:.4f}<extra></extra>'
  }], {
    title: 'Top Cities by Adjusted Occupancy Rate',
    paper_bgcolor: 'rgba(0,0,0,0)',
    plot_bgcolor: 'rgba(0,0,0,0)',
    margin: { l: 140, r: 24, t: 58, b: 48 },
    xaxis: { title: 'Adjusted Occupancy Rate' },
    yaxis: { automargin: true }
  }, { responsive: true, displayModeBar: false });
}

function plotCityHouseRanking(scenario) {
  const items = scenario.rankedCityHouse.slice(0, 15);
  Plotly.newPlot('cityHouseChart', [{
    type: 'bar',
    orientation: 'h',
    y: items.map((item) => item.label).reverse(),
    x: items.map((item) => item.adj_airbnb_yroi).reverse(),
    marker: { color: '#c5733e' },
    hovertemplate: '%{y}<br>ADJ_AIRBNB_YROI: %{x:.4f}<extra></extra>'
  }], {
    title: 'City + House Type Ranking by ADJ_AIRBNB_YROI',
    paper_bgcolor: 'rgba(0,0,0,0)',
    plot_bgcolor: 'rgba(0,0,0,0)',
    margin: { l: 200, r: 24, t: 58, b: 48 },
    xaxis: { title: 'ADJ_AIRBNB_YROI' },
    yaxis: { automargin: true }
  }, { responsive: true, displayModeBar: false });
}

function plotRoiComparison(scenario) {
  const items = scenario.rankedCityHouse.slice(0, 12);
  Plotly.newPlot('roiChart', [
    {
      type: 'bar',
      name: 'ADJ_AIRBNB_YROI',
      x: items.map((item) => item.label),
      y: items.map((item) => item.adj_airbnb_yroi),
      marker: { color: '#2f7c85' }
    },
    {
      type: 'bar',
      name: 'RENT_YROI',
      x: items.map((item) => item.label),
      y: items.map((item) => item.rent_yroi),
      marker: { color: '#d8a448' }
    }
  ], {
    title: 'ROI Comparison: ADJ_AIRBNB_YROI vs RENT_YROI',
    barmode: 'group',
    paper_bgcolor: 'rgba(0,0,0,0)',
    plot_bgcolor: 'rgba(0,0,0,0)',
    margin: { l: 56, r: 24, t: 58, b: 120 },
    xaxis: { tickangle: -24 },
    yaxis: { title: 'ROI' }
  }, { responsive: true, displayModeBar: false });
}

function plotFinancialChart(decisionRows) {
  Plotly.newPlot('financialChart', [
    {
      type: 'bar',
      name: 'House Price',
      x: decisionRows.map((row) => `${row.city} | ${row.house_type}`),
      y: decisionRows.map((row) => row.house_price),
      marker: { color: '#6f8f72' }
    },
    {
      type: 'scatter',
      mode: 'lines+markers',
      name: 'Cumulative House Price',
      x: decisionRows.map((row) => `${row.city} | ${row.house_type}`),
      y: decisionRows.map((row) => row.cumulativeHousePrice),
      line: { color: '#17324d', width: 3 }
    },
    {
      type: 'scatter',
      mode: 'lines',
      name: 'Budget',
      x: decisionRows.map((row) => `${row.city} | ${row.house_type}`),
      y: decisionRows.map(() => state.budget),
      line: { color: '#c73d3d', dash: 'dash', width: 2 }
    }
  ], {
    title: 'Financial Valuation: House Price vs Budget',
    paper_bgcolor: 'rgba(0,0,0,0)',
    plot_bgcolor: 'rgba(0,0,0,0)',
    margin: { l: 64, r: 24, t: 58, b: 140 },
    xaxis: { tickangle: -24 },
    yaxis: { title: 'EUR' }
  }, { responsive: true, displayModeBar: false });
}

function renderDecisionTable(decisionRows) {
  elements.tableCaption.textContent = `Top ${decisionRows.length} rows shown from the Final Dashboard / Step 4 reconstruction. Sorted by ${metricOptions[state.metric].label}. The shortlist is budget-aware, search-aware, and capped at 25 rows for readability.`;
  elements.tableBody.innerHTML = decisionRows.map((row, index) => `
    <tr>
      <td>${index + 1}</td>
      <td>${row.city}</td>
      <td>${row.house_type}</td>
      <td>${formatPercent(row.adjusted_occupancy_rate)}</td>
      <td>${formatPercent(row.adj_airbnb_yroi)}</td>
      <td>${formatPercent(row.rent_yroi)}</td>
      <td>${formatRatio(row.roi_ratio)}</td>
      <td>${formatCurrency(row.house_price)}</td>
      <td>${formatCurrency(row.adj_airbnb_new)}</td>
      <td>${formatCurrency(row.annual_rent)}</td>
      <td>${formatCurrency(row.service_cost_new)}</td>
      <td>${formatCurrency(row.cumulativeHousePrice)}</td>
      <td>${formatCurrency(row.differenceTotal)}</td>
      <td>${formatCurrency(row.scenarioLoanAmount)}</td>
      <td>${formatCurrency(row.annualInterestCost)}</td>
    </tr>
  `).join('');
}

function renderEmptyState() {
  ['topCitiesChart', 'cityHouseChart', 'roiChart', 'financialChart'].forEach((id) => {
    document.getElementById(id).innerHTML = '<div class="empty-state">No rows match the current filters.</div>';
  });
  elements.tableBody.innerHTML = '';
  elements.tableCaption.textContent = 'No rows match the current filters.';
}

function render() {
  const rows = filteredRows();
  setMetricNotice();
  if (!rows.length) {
    renderEmptyState();
    return;
  }

  const scenario = getScenario(rows);
  const decisionRows = getDecisionRows(rows, scenario.rankedCityHouse);
  renderKpis(rows, scenario, decisionRows);
  plotTopCities(scenario);
  plotCityHouseRanking(scenario);
  plotRoiComparison(scenario);
  plotFinancialChart(decisionRows);
  renderDecisionTable(decisionRows);
}

initialiseControls();
render();
